import { useState, useEffect, useContext } from 'react';
import { Link } from 'react-router-dom';
import { toast } from 'react-toastify';
import { FaPlus } from 'react-icons/fa';
import AuthContext from '../context/AuthContext';
import ForumPostCard from '../components/ForumPostCard';
import Spinner from '../components/Spinner';
import forumService from '../api/forumService';

function Forum() {
  const [posts, setPosts] = useState([]);
  const [loading, setLoading] = useState(true);
  const { isAuthenticated } = useContext(AuthContext);

  useEffect(() => {
    const fetchPosts = async () => {
      try {
        const data = await forumService.getForumPosts();
        setPosts(data);
      } catch (error) {
        toast.error('Error fetching forum posts');
      } finally {
        setLoading(false);
      }
    };

    fetchPosts();
  }, []);

  if (loading) {
    return <Spinner />;
  }

  return (
    <div>
      <div className="flex justify-between items-center mb-6">
        <h1 className="text-3xl font-bold text-green-700">Farmer's Forum</h1>
        {isAuthenticated && (
          <Link
            to="/forum/new"
            className="bg-green-600 hover:bg-green-700 text-white font-bold py-2 px-4 rounded flex items-center"
          >
            <FaPlus className="mr-2" /> New Post
          </Link>
        )}
      </div>

      <div className="bg-white p-6 rounded-lg shadow-md mb-8">
        <h2 className="text-xl font-semibold text-gray-800 mb-4">
          Welcome to the Farmer's Community Forum
        </h2>
        <p className="text-gray-600">
          Connect with fellow farmers, share knowledge, ask questions, and
          contribute to the farming community. Feel free to create a new post or
          browse existing discussions.
        </p>
      </div>

      {posts.length === 0 ? (
        <div className="bg-white p-6 rounded-lg shadow-md text-center">
          <p className="text-gray-500">
            There are no forum posts yet. Be the first to start a discussion!
          </p>
          {isAuthenticated ? (
            <Link
              to="/forum/new"
              className="mt-4 inline-block bg-green-600 hover:bg-green-700 text-white font-bold py-2 px-4 rounded"
            >
              Create Post
            </Link>
          ) : (
            <Link
              to="/login"
              className="mt-4 inline-block bg-green-600 hover:bg-green-700 text-white font-bold py-2 px-4 rounded"
            >
              Login to Post
            </Link>
          )}
        </div>
      ) : (
        <div className="space-y-6">
          {posts.map((post) => (
            <ForumPostCard key={post._id} post={post} />
          ))}
        </div>
      )}
    </div>
  );
}

export default Forum;
